  function apply(){
    var CF = window.CHAMP_FULL; if(!CF) return;
    for(var ck in FIX){ var en = CF[ck]; if(!en) continue; var mm = FIX[ck];
      for(var ek in mm){ var m = en[ek]; if(!m || !m.phases) continue; var sides = mm[ek];
        for(var i=0;i<m.phases.length && i<sides.length;i++){ if(sides[i] && m.phases[i]) m.phases[i].side = sides[i]; }
      }
    }
  }
